content.message:
Loaded 3 tools:

<tool_info>
  <name>add_character_condition</name>
  <description>Add condition (buff/debuff) to the PROTAGONIST. Character tools are for protagonist only; use npc tools for NPCs.</description>
  <parameters>
{
  name: string; // Condition name.
  type?: "normal" | "wound" | "poison" | "buff" | "debuff" | "mental" | "curse" | "stun" | "unconscious" | "tired" | "dead"; // Type.
  visible?: {
    description?: string; // Visible description of the condition.
    perceivedSeverity?: string; // How severe it appears to be. Must be in target language.
  }; // Visible props.
  hidden?: {
    trueCause?: string; // The true cause of this condition.
    actualSeverity?: string; // Actual severity level.
    progression?: string; // How the condition will progress.
    cure?: string; // How to cure or remove this condition.
  }; // Hidden props.
  effects?: {
    visible?: Array<string>;
    hidden?: Array<string>;
  }; // Effects.
  icon?: string; // Emoji.
}
  </parameters>
</tool_info>

<tool_info>
  <name>add_quest</name>
  <description>Add quest.</description>
  <parameters>
{
  title: string; // Quest title.
  type?: "main" | "side" | "hidden"; // Quest type.
  visible?: {
    description?: string; // The apparent objective.
    objectives?: Array<string>; // Visible quest objectives.
  }; // Visible props.
  hidden?: {
    trueDescription?: string; // The hidden truth or real purpose.
    trueObjectives?: Array<string>; // True hidden objectives.
    secretOutcome?: string; // Secret outcome if quest is completed.
    twist?: string; // Hidden complication or moral dilemma. The quest is never what it seems.
  }; // Hidden props (AI/GM).
  icon?: string; // Emoji.
  notes?: string; // Notes.
}
  </parameters>
</tool_info>

<tool_info>
  <name>add_character_attribute</name>
  <description>Add numeric attribute to the PROTAGONIST. Character tools are for protagonist only; use npc tools for NPCs.</description>
  <parameters>
{
  name: string; // Attribute name.
  value: number; // Value.
  maxValue?: number; // Max value.
  color?: "red" | "blue" | "green" | "yellow" | "purple" | "gray"; // Color.
}
  </parameters>
</tool_info>
